window.bookSummaryJSON = "<p><b>Special Note: Please listen to </b><b><i>Quicksilver </i></b><b>before going behind the scenes with Kingfisher! Or risk being flung into the middle of the battle.</b></p> <p>Previously only available on Callie Hart's website, these scenes (written from Kingfisher's point of view rather than Saeris') are now brought to life in audio by popular demand. The scenes included are \"The Gates (Parts 1 &amp; 2)\" and \"The Fox. The Boots. The Dress.\"</p> <p><i>Narrated in duet style.</i></p>"; 
